 6→// ================================================================
 7→// LANGUAGE SELECTOR — Dropdown sélecteur de langue
 8→// Styles : glass-panel, cohérent avec le design CitedBy.ai
 9→// ================================================================
10→
11→interface LanguageSelectorProps {
12→  /** Compact mode : affiche uniquement le drapeau + code (pour la navbar) */
13→  compact?: boolean;
14→  /** Classe CSS additionnelle */
15→  className?: string;
16→}
17→
18→export const LanguageSelector: React.FC<LanguageSelectorProps> = ({ compact = false, className = '' }) => {
19→  const { locale, setLocale } = useTranslation();
20→  const [isOpen, setIsOpen] = useState(false);
21→  const ref = useRef<HTMLDivElement>(null);
22→
23→  const currentLocale = SUPPORTED_LOCALES.find(l => l.code === locale)!;
24→
25→  // Close dropdown on outside click
26→  useEffect(() => {
27→    const handleClickOutside = (e: MouseEvent) => {
28→      if (ref.current && !ref.current.contains(e.target as Node)) {
29→        setIsOpen(false);
30→      }
31→    };
32→    document.addEventListener('mousedown', handleClickOutside);
33→    return () => document.removeEventListener('mousedown', handleClickOutside);
34→  }, []);
35→
36→  const handleSelect = (code: Locale) => {
37→    setLocale(code);
38→    setIsOpen(false);
39→  };
40→
41→  return (
42→    <div ref={ref} className={`relative ${className}`}>
43→      {/* Trigger button */}
44→      <button
45→        onClick={() => setIsOpen(!isOpen)}
46→        className={`flex items-center gap-2 rounded-lg border border-white/10 transition-all hover:border-primary/50 hover:bg-primary/10 group ${
47→          compact
48→            ? 'px-2.5 py-1.5 bg-white/5'
49→            : 'px-3 py-2 bg-[#1a1d21]'
50→        }`}
51→        title={`Language: ${currentLocale.nativeName}`}
52→      >
53→        <span className="text-base leading-none">{currentLocale.flag}</span>
54→        {compact ? (
55→          <span className="text-xs font-bold text-gray-300 group-hover:text-primary uppercase">{currentLocale.code}</span>
56→        ) : (
57→          <>
58→            <span className="text-sm font-medium text-gray-300 group-hover:text-white">{currentLocale.nativeName}</span>
59→            <Globe size={14} className="text-gray-500 group-hover:text-primary" />
60→          </>
61→        )}
62→      </button>
63→
64→      {/* Dropdown */}
65→      {isOpen && (
66→        <div className="absolute top-full mt-2 right-0 z-[100] min-w-[180px] bg-[#0f1115] border border-white/10 rounded-xl shadow-2xl shadow-black/50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
67→          {SUPPORTED_LOCALES.map((loc) => (
68→            <button
69→              key={loc.code}
70→              onClick={() => handleSelect(loc.code)}
71→              className={`w-full flex items-center gap-3 px-4 py-3 text-left transition-all ${
72→                locale === loc.code
73→                  ? 'bg-primary/10 text-primary border-l-2 border-primary'
74→                  : 'text-gray-400 hover:bg-white/5 hover:text-white border-l-2 border-transparent'
75→              }`}
76→            >
77→              <span className="text-lg leading-none">{loc.flag}</span>
78→              <div className="flex flex-col">
79→                <span className="text-sm font-medium">{loc.nativeName}</span>
80→                <span className="text-[10px] text-gray-500 uppercase">{loc.name}</span>
81→              </div>
82→              {locale === loc.code && (
83→                <span className="ml-auto text-primary text-xs">&#10003;</span>
84→              )}
85→            </button>
86→          ))}
87→        </div>
88→      )}
89→    </div>
90→  );
91→};
92→
93→export default LanguageSelector;
